+// IsRemote returns true when the config points to a non-local Dolt server.
+// Empty host, "127.0.0.1", "localhost", "::1", and "[::1]" are all considered local.
+func (c *Config) IsRemote() bool {
+	switch strings.ToLower(c.Host) {
