+func TestIsRemote(t *testing.T) {
+	tests := []struct {
+		host string
+		want bool
+	}{
+		{"", false},
+		{"127.0.0.1", false},
+		{"localhost", false},
+		{"Localhost", false},
+		{"LOCALHOST", false},
+		{"::1", false},
+		{"[::1]", false},
+		{"10.0.0.5", true},
+		{"dolt.internal", true},
+		{"192.168.1.100", true},
+	}
+	for _, tt := range tests {
+		c := &Config{Host: tt.host}
+		got := c.IsRemote()
+		if got != tt.want {
+			t.Errorf("Config{Host: %q}.IsRemote() = %v, want %v", tt.host, got, tt.want)
+		}
+	}
+}
